const speakWord = (word) => {
  if (word) {
    console.log("Speaking word:", word);  // Add log to check if the word is being passed correctly
    const synth = window.speechSynthesis;
    const utterance = new SpeechSynthesisUtterance(word);
    utterance.lang = "en-ZA"; // South African English accent (optional, depending on browser support)
    utterance.rate = 0.9; // Slightly slower than normal
    utterance.pitch = 1.0; // Neutral pitch
    utterance.volume = 1.0; // Max volume
    synth.speak(utterance);
    utterance.onstart = () => console.log("Speech started");
    utterance.onend = () => console.log("Speech ended");
  } else {
    console.log("No word to speak.");
  }
};
